/*
 * Memory Game

 * STEPS:
 *  - Press any button to start. The device flashes a growing sequence of
 *    LEDs (with matching tones); repeat it back in order using the buttons.
 *  - Correct round -> sequence grows by one step and plays back faster.
 *  - Wrong button, or no input within the timeout -> game over, score shown.
 *    shows a "NEW HIGH SCORE" screen with a fanfare tone.
 *  - Buttons register a click on RELEASE, not on press, with debounce so a
 *    held or bouncy button only ever counts once.
 */

#include <Wire.h>
#include <LiquidCrystal_I2C.h>
#include <EEPROM.h>

// ---------- Pin map ----------
const int LED_PINS[4]    = {2, 3, 4, 5};
const int BUTTON_PINS[4] = {6, 7, 8, 9};
#define BUZZER_PIN 10

// ---------- Musical notes per button ----------
const int NOTE_FREQ[4] = {262, 330, 392, 494}; // C4, E4, G4, B4

// ---------- Objects ----------
LiquidCrystal_I2C lcd(0x27, 16, 2); 

// ---------- State machine ----------
enum State { IDLE, SHOW_SEQUENCE, WAIT_INPUT, CORRECT_PAUSE, GAME_OVER, NEW_HIGH_SCORE };
State state = IDLE;

// ---------- Game data ----------
const int MAX_LEVEL = 32;
int sequence[MAX_LEVEL];
int currentLevel = 0;   
int inputIndex = 0;     

const int EEPROM_HIGH_SCORE_ADDR = 0;
int highScore = 0;

// ---------- Sequence playback (non-blocking) ----------
int playbackIndex = 0;
bool ledOnPhase = true;
unsigned long stepStartTime = 0;

// ---------- Button feedback flash (non-blocking) ----------
int feedbackLed = -1;
unsigned long feedbackStart = 0;
const unsigned long FEEDBACK_DURATION_MS = 300;

// ---------- Input timeout ----------
unsigned long lastInputAt = 0;
const unsigned long INPUT_TIMEOUT_MS = 5000;

// ---------- Debounce (release-triggered: only fires once per full press+release) ----------
bool lastRawState[4]  = {HIGH, HIGH, HIGH, HIGH};
bool stableState[4]   = {HIGH, HIGH, HIGH, HIGH};
bool armed[4]         = {false, false, false, false}; 
unsigned long lastChangeTime[4] = {0, 0, 0, 0};
const unsigned long DEBOUNCE_MS = 40;

// ---------- Misc timing ----------
unsigned long stateEnteredAt = 0;

void setup() {
  Serial.begin(9600);

  for (int i = 0; i < 4; i++) {
    pinMode(LED_PINS[i], OUTPUT);
    pinMode(BUTTON_PINS[i], INPUT_PULLUP);
    digitalWrite(LED_PINS[i], LOW);
  }
  pinMode(BUZZER_PIN, OUTPUT);

  Wire.begin();
  lcd.init();
  lcd.backlight();

  EEPROM.get(EEPROM_HIGH_SCORE_ADDR, highScore);
  if (highScore < 0 || highScore > MAX_LEVEL) highScore = 0; 

  randomSeed(analogRead(A0)); 

  showIdleScreen();
}

void loop() {
  unsigned long now = millis();

  updateFeedbackFlash(now);

  switch (state) {
    case IDLE:
      handleIdle();
      break;
    case SHOW_SEQUENCE:
      handleShowSequence(now);
      break;
    case WAIT_INPUT:
      handleWaitInput(now);
      break;
    case CORRECT_PAUSE:
      handleCorrectPause(now);
      break;
    case GAME_OVER:
      handleGameOver(now);
      break;
    case NEW_HIGH_SCORE:
      handleNewHighScore(now);
      break;
  }
}

// ---------------- State handlers ----------------

void handleIdle() {
  for (int i = 0; i < 4; i++) {
    if (buttonPressed(i)) {
      startNewGame();
      return;
    }
  }
}

void handleShowSequence(unsigned long now) {
  if (playbackIndex >= currentLevel) {
    inputIndex = 0;
    lastInputAt = now;
    changeState(WAIT_INPUT);
    return;
  }

  unsigned long onDuration = playbackSpeed();
  unsigned long gapDuration = onDuration / 2;

  if (ledOnPhase) {
    digitalWrite(LED_PINS[sequence[playbackIndex]], HIGH);
    tone(BUZZER_PIN, NOTE_FREQ[sequence[playbackIndex]]);

    if (now - stepStartTime >= onDuration) {
      digitalWrite(LED_PINS[sequence[playbackIndex]], LOW);
      noTone(BUZZER_PIN);
      ledOnPhase = false;
      stepStartTime = now;
    }
  } else {
    if (now - stepStartTime >= gapDuration) {
      playbackIndex++;
      ledOnPhase = true;
      stepStartTime = now;
    }
  }
}

void handleWaitInput(unsigned long now) {
  if (now - lastInputAt > INPUT_TIMEOUT_MS) {
    endGame();
    return;
  }

  for (int i = 0; i < 4; i++) {
    if (buttonPressed(i)) {
      Serial.print("Button index ");
      Serial.print(i);
      Serial.print(" (pin ");
      Serial.print(BUTTON_PINS[i]);
      Serial.print(") clicked. Expected index: ");
      Serial.println(sequence[inputIndex]);

      lastInputAt = now;
      flashFeedback(i, now);

      if (i == sequence[inputIndex]) {
        inputIndex++;
        if (inputIndex >= currentLevel) {
          changeState(CORRECT_PAUSE);
        }
      } else {
        endGame();
      }
      return; 
    }
  }
}

void handleCorrectPause(unsigned long now) {
  if (now - stateEnteredAt > 500) {
    addRandomStep();
    playbackIndex = 0;
    ledOnPhase = true;
    stepStartTime = now;
    changeState(SHOW_SEQUENCE);
  }
}

void handleGameOver(unsigned long now) {
  if (now - stateEnteredAt > 3000) {
    if (currentLevel - 1 > highScore) {
      highScore = currentLevel - 1;
      EEPROM.put(EEPROM_HIGH_SCORE_ADDR, highScore);
      changeState(NEW_HIGH_SCORE);
    } else {
      changeState(IDLE);
    }
  }
}

void handleNewHighScore(unsigned long now) {
  if (now - stateEnteredAt > 3000) {
    changeState(IDLE);
  }
}

// ---------------- Game logic helpers ----------------

void startNewGame() {
  currentLevel = 0;
  addRandomStep();
  playbackIndex = 0;
  ledOnPhase = true;
  stepStartTime = millis();
  changeState(SHOW_SEQUENCE);
}

void addRandomStep() {
  if (currentLevel < MAX_LEVEL) {
    sequence[currentLevel] = random(0, 4);
    currentLevel++;
  }
}

void endGame() {
  changeState(GAME_OVER);
}

unsigned long playbackSpeed() {
  long speed = 1200 - (currentLevel * 15);
  if (speed < 500) speed = 500;
  return (unsigned long)speed;
}

// ---------------- Input helpers ----------------


bool buttonPressed(int i) {
  unsigned long now = millis();
  bool raw = digitalRead(BUTTON_PINS[i]);

  if (raw != lastRawState[i]) {
    lastChangeTime[i] = now; 
    lastRawState[i] = raw;
  }

  if ((now - lastChangeTime[i]) > DEBOUNCE_MS && raw != stableState[i]) {
    stableState[i] = raw;

    if (stableState[i] == LOW) {
      armed[i] = true; 
    } else if (armed[i]) {
      armed[i] = false;
      return true; 
    }
  }

  return false;
}

void flashFeedback(int i, unsigned long now) {
  digitalWrite(LED_PINS[i], HIGH);
  tone(BUZZER_PIN, NOTE_FREQ[i], FEEDBACK_DURATION_MS);
  feedbackLed = i;
  feedbackStart = now;
}

void updateFeedbackFlash(unsigned long now) {
  if (feedbackLed != -1 && (now - feedbackStart) >= FEEDBACK_DURATION_MS) {
    digitalWrite(LED_PINS[feedbackLed], LOW);
    feedbackLed = -1;
  }
}

// ---------------- Display ----------------

void changeState(State newState) {
  state = newState;
  stateEnteredAt = millis();

  switch (newState) {
    case IDLE:
      showIdleScreen();
      break;
    case SHOW_SEQUENCE:
      lcd.clear();
      lcd.setCursor(0, 0);
      lcd.print("Watch closely...");
      lcd.setCursor(0, 1);
      lcd.print("Level: ");
      lcd.print(currentLevel);
      break;
    case WAIT_INPUT:
      lcd.clear();
      lcd.setCursor(0, 0);
      lcd.print("Your turn!");
      lcd.setCursor(0, 1);
      lcd.print("Level: ");
      lcd.print(currentLevel);
      break;
    case CORRECT_PAUSE:
      lcd.clear();
      lcd.setCursor(0, 0);
      lcd.print("Correct!");
      break;
    case GAME_OVER:
      lcd.clear();
      lcd.setCursor(0, 0);
      lcd.print("Game Over!");
      lcd.setCursor(0, 1);
      lcd.print("Score: ");
      lcd.print(currentLevel - 1);
      failBuzz();
      break;
    case NEW_HIGH_SCORE:
      lcd.clear();
      lcd.setCursor(0, 0);
      lcd.print("NEW HIGH SCORE!");
      lcd.setCursor(0, 1);
      lcd.print(highScore);
      winFanfare();
      break;
  }
}

void showIdleScreen() {
  lcd.clear();
  lcd.setCursor(0, 0);
  lcd.print("Press any button");
  lcd.setCursor(0, 1);
  lcd.print("High score: ");
  lcd.print(highScore);
}

// ---------------- Sound effects ----------------

void failBuzz() {
  tone(BUZZER_PIN, 150, 600); 
}

void winFanfare() {

  tone(BUZZER_PIN, 523, 150); delay(150);
  tone(BUZZER_PIN, 659, 150); delay(150);
  tone(BUZZER_PIN, 784, 300); delay(300);
}
